import sys

def main():
    import sys
    input = sys.stdin.read
    N, S = input().split()
    N = int(N)
    S = S.strip()

    # Define the winning move for each Aoki's move
    win_move = {'R': 'P', 'P': 'S', 'S': 'R'}

    # Define the losing move for each Aoki's move
    lose_move = {'R': 'S', 'P': 'R', 'S': 'P'}

    # We will use dynamic programming
    # dp[i][m] = max wins up to i-th game with move m
    # m can be 'R', 'P', 'S'
    # Initialize dp with -infinity
    from collections import defaultdict

    dp = [defaultdict(lambda: -1) for _ in range(N)]

    # Initialize first move
    for m in ['R', 'P', 'S']:
        if win_move[m] == S[0]:
            dp[0][m] = 1
        elif lose_move[m] == S[0]:
            dp[0][m] = 0
        else:
            dp[0][m] = -1  # Not allowed

    for i in range(1, N):
        for prev_m in ['R', 'P', 'S']:
            if dp[i-1][prev_m] == -1:
                continue
            for curr_m in ['R', 'P', 'S']:
                if curr_m == prev_m:
                    continue
                if win_move[curr_m] == S[i]:
                    dp[i][curr_m] = max(dp[i][curr_m], dp[i-1][prev_m] + 1)
                elif lose_move[curr_m] == S[i]:
                    dp[i][curr_m] = max(dp[i][curr_m], dp[i-1][prev_m])
                else:
                    continue

    print(max(dp[N-1].values()))

if __name__ == "__main__":
    main()
